fn build(params: &ParameterSet, sample_rate: f32, layout: AudioChannelLayout) -> Result<BlockProcessor> {
    let bypass = required_bool(params, "bypass").map_err(anyhow::Error::msg)?;
    let wetdry = required_f32(params, "wetdry").map_err(anyhow::Error::msg)?;
    let b1 = required_f32(params, "b1").map_err(anyhow::Error::msg)?;
    let b2 = required_f32(params, "b2").map_err(anyhow::Error::msg)?;
    let b3 = required_f32(params, "b3").map_err(anyhow::Error::msg)?;
    let b4 = required_f32(params, "b4").map_err(anyhow::Error::msg)?;
    let b5 = required_f32(params, "b5").map_err(anyhow::Error::msg)?;
    let b6 = required_f32(params, "b6").map_err(anyhow::Error::msg)?;
    let b7 = required_f32(params, "b7").map_err(anyhow::Error::msg)?;
    let b8 = required_f32(params, "b8").map_err(anyhow::Error::msg)?;
    let res = required_f32(params, "res").map_err(anyhow::Error::msg)?;
    let start = required_f32(params, "start").map_err(anyhow::Error::msg)?;
    let end = required_f32(params, "end").map_err(anyhow::Error::msg)?;
    let tempo = required_f32(params, "tempo").map_err(anyhow::Error::msg)?;
    let stdf = required_f32(params, "stdf").map_err(anyhow::Error::msg)?;
    let subd = required_f32(params, "subd").map_err(anyhow::Error::msg)?;
    let autopan = required_f32(params, "autopan").map_err(anyhow::Error::msg)?;
    let rev = required_bool(params, "rev").map_err(anyhow::Error::msg)?;
    let stage = required_f32(params, "stage").map_err(anyhow::Error::msg)?;
    let lib_path = lv2::resolve_lv2_lib(PLUGIN_BINARY)?;
    let bundle_path = lv2::resolve_lv2_bundle(PLUGIN_DIR)?;

    let control_ports: &[(usize, f32)] = &[
        (PORT_CTRL_BYPASS, if bypass { 1.0 } else { 0.0 }),
        (PORT_CTRL_WETDRY, wetdry),
        (PORT_CTRL_B1, b1),
        (PORT_CTRL_B2, b2),
        (PORT_CTRL_B3, b3),
        (PORT_CTRL_B4, b4),
        (PORT_CTRL_B5, b5),
        (PORT_CTRL_B6, b6),
        (PORT_CTRL_B7, b7),
        (PORT_CTRL_B8, b8),
        (PORT_CTRL_RES, res),
        (PORT_CTRL_START, start),
        (PORT_CTRL_END, end),
        (PORT_CTRL_TEMPO, tempo),
        (PORT_CTRL_STDF, stdf),
        (PORT_CTRL_SUBD, subd),
        (PORT_CTRL_AUTOPAN, autopan),
        (PORT_CTRL_REV, if rev { 1.0 } else { 0.0 }),
        (PORT_CTRL_STAGE, stage),
    ];

    let processor = lv2::build_stereo_lv2_processor(&lib_path, PLUGIN_URI, sample_rate as f64, &bundle_path, &[PORT_AUDIO_IN_INPUT_L, PORT_AUDIO_IN_INPUT_R], &[PORT_AUDIO_OUT_OUTPUT_L, PORT_AUDIO_OUT_OUTPUT_R], control_ports)?;
    let _ = layout;
    Ok(BlockProcessor::Stereo(Box::new(processor)))
}

